#include<iostream>#include<algorithm>#include<vector>#include<climits> #define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<ll> a(n);        int op=0;        int curr=-1;        for(int i=0;i<n;i++){            cin>>a[i];            if(a[i]>=curr){                op++;                curr=a[i];            }                    }        cout<<op<<"\n";     }}